  ('a6d85eef-de27-11f0-8727-001a7dda7113', 'DPS Group Global is a global consulting, engineering, and construction management company with an office in Europe. The company uses Virtual Design and Construction (VDC) methodologies alongside BIM technologies to serve high-tech industries.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d88800-de27-11f0-8727-001a7dda7113', 'BIM Facility AG is a BIM company mentioned among the "Top Building Information Modeling Solutions Providers" in Europe. The company provides BIM services and is based in Switzerland.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d8e67f-de27-11f0-8727-001a7dda7113', 'Powerkh is a UK-based company that offers MEP (Mechanical, Electrical, and Plumbing) BIM services. It has offices in Ukraine and the USA and provides a variety of BIM outsourcing services, including content creation and 3D modeling.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d90951-de27-11f0-8727-001a7dda7113', 'QeBIM Services is a BIM service provider based in the UK, offering BIM modeling services in Europe. The company specializes in architectural, structural, and MEP modeling.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d929fe-de27-11f0-8727-001a7dda7113', 'Harmony AT is a German company located in Kundert. It offers BIM modeling services for clients in Europe.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d94d0f-de27-11f0-8727-001a7dda7113', 'Small BIM Modeling Companies', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d98c2b-de27-11f0-8727-001a7dda7113', 'bimspot is an Austrian startup founded in 2018 that provides a SaaS platform for BIM-oriented collaboration. Its technology allows for the development of digital building models independent of specific software choices.', 'BIM / Construction', '["BIM Services","Geospatial Software"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d9b626-de27-11f0-8727-001a7dda7113', 'BIM-Lab Ltd - MEP consultancy is a specialized MEP BIM consultancy located in London, UK. It focuses on mechanical, electrical, and plumbing services for construction projects.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d9d914-de27-11f0-8727-001a7dda7113', 'BIMdesign Consulting is based in Spain and offers BIM project execution for both architectural design and MEP installations. It also provides BIM implementation and training for individuals and companies.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6d9f9b7-de27-11f0-8727-001a7dda7113', 'BIM Consulting, s.r.o. is a Czech company located in Prague. It offers BIM management consulting to institutions and companies, covering process digitization, project monitoring, data management, and standardization.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6da1a9d-de27-11f0-8727-001a7dda7113', 'Digital Engineering Works (DEWorks) is a UK-based company specializing in BIM content creation. It provides services to clients within the UK and Europe.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6db28ae-de27-11f0-8727-001a7dda7113', 'Sagiton is a BIM modeling company located in Poland. It offers BIM services to clients in Europe and focuses on digital construction.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
  ('a6db549c-de27-11f0-8727-001a7dda7113', 'Bimpact Designs is a BIM outsourcing company that works with clients in Europe. It specializes in architectural, structural, and MEP BIM services and provides solutions for construction projects.', 'BIM / Construction', '["BIM Services"]', NULL, '0.00', 'inactive', ST_GeomFromText('POINT(78.9629 20.5937)')),
