  ('3b4f078c-58f3-11f1-bd30-cc28aac91a8b', 'c288424d-c135-426e-afa5-a72040ae6476', 'Smart City Digital Twin and Urban Mobility GIS Platform Development', 'The city administration seeks proposals from qualified geospatial technology vendors to design and implement a Smart City GIS platform with integrated urban digital twin capabilities. The project will include development of a centralized geospatial data infrastructure for urban planning, traffic management, zoning analysis, utility overlays, and citizen service mapping. The selected vendor will integrate multi-source spatial datasets including satellite imagery, LiDAR, cadastral maps, IoT sensor feeds, transportation networks, and building footprints into a unified web-based GIS platform. The scope includes 3D city modeling, traffic heatmap generation, land-use change detection, flood-risk mapping, and AI-assisted urban growth analysis. The platform must support real-time dashboards, mobile accessibility, spatial analytics, and interoperability with existing municipal ERP and smart infrastructure systems.', '180000.00', 'closed', NULL, '2026-05-26 11:08:32', '2026-06-10 18:30:00', '2028-06-23 18:30:00', '2026-06-13 19:05:00', 'public', 'Test1pdf', 'test90@gmail.com', NULL, NULL, 0, NULL, NULL, NULL, 'v1.0'),
  ('3b4f08a5-58f3-11f1-bd30-cc28aac91a8b', '9c76396b-fef9-43a2-b6fa-005baaa21e28', 'test1', 'test1', '4999.98', 'closed', NULL, '2026-05-26 11:08:32', '2026-01-30 18:30:00', '2026-02-19 18:30:00', '2026-02-04 20:10:00', 'public', 'sar', 'test99@gmail.com', NULL, 1144, 0, NULL, NULL, NULL, 'v1.0'),
  ('3b4f09ae-58f3-11f1-bd30-cc28aac91a8b', 'c288424d-c135-426e-afa5-a72040ae6476', 'test2', 'test2', '10000.00', 'open', NULL, '2026-05-26 11:08:32', '2026-02-26 18:30:00', '2026-03-12 18:30:00', '2026-03-08 20:10:00', 'public', 'test2', 'test90@gmail.com', NULL, NULL, 0, NULL, NULL, NULL, 'v1.0'),
  ('3b4f0abc-58f3-11f1-bd30-cc28aac91a8b', 'c288424d-c135-426e-afa5-a72040ae6476', 'Transmission Network Asset Mapping and Predictive Utility GIS System', 'A regional power distribution utility invites proposals for implementation of a geospatial asset management and predictive maintenance system for transmission and distribution infrastructure. The project aims to create a centralized GIS-based utility network model integrating substations, transformers, transmission lines, smart meters, and outage management systems. The selected vendor will conduct field data collection, GPS-based asset validation, drone-assisted corridor inspections, and integration of SCADA and IoT sensor feeds. The solution should support predictive analytics for asset failure detection, vegetation encroachment analysis, line-loss mapping, and outage impact visualization.', '250000.00', 'closed', NULL, '2026-05-26 11:08:32', '2026-06-27 18:30:00', '2027-04-11 18:30:00', '2026-05-20 00:46:00', 'public', 'Test2pdf', 'test90@gmail.com', NULL, NULL, 0, NULL, NULL, NULL, 'v1.0'),
