  ('e7b63bf3-58f3-11f1-bd30-cc28aac91a8b', 'c288424d-c135-426e-afa5-a72040ae6476', 'Test123', 'awdad', '50000.00', 'open', NULL, '2026-05-26 11:13:21', '2026-05-09 18:30:00', '2026-05-23 18:30:00', '2026-05-13 00:52:00', 'public', 'Sar', 'test90@gmail.com', NULL, NULL, 1, NULL, NULL, '2026-05-15 19:29:57', 'v1.0'),
  ('e7b63d1a-58f3-11f1-bd30-cc28aac91a8b', 'c288424d-c135-426e-afa5-a72040ae6476', 'Smart City Digital Twin and Urban Mobility GIS Platform Development', 'The city administration seeks proposals from qualified geospatial technology vendors to design and implement a Smart City GIS platform with integrated urban digital twin capabilities. The project will include development of a centralized geospatial data infrastructure for urban planning, traffic management, zoning analysis, utility overlays, and citizen service mapping. The selected vendor will integrate multi-source spatial datasets including satellite imagery, LiDAR, cadastral maps, IoT sensor feeds, transportation networks, and building footprints into a unified web-based GIS platform. The scope includes 3D city modeling, traffic heatmap generation, land-use change detection, flood-risk mapping, and AI-assisted urban growth analysis. The platform must support real-time dashboards, mobile accessibility, spatial analytics, and interoperability with existing municipal ERP and smart infrastructure systems.', '180000.00', 'closed', NULL, '2026-05-26 11:13:21', '2026-06-11 18:30:00', '2028-06-24 18:30:00', '2026-06-14 00:35:00', 'public', 'Test1pdf', 'test90@gmail.com', NULL, NULL, 0, NULL, NULL, NULL, 'v1.0'),
  ('e7b63e47-58f3-11f1-bd30-cc28aac91a8b', '9c76396b-fef9-43a2-b6fa-005baaa21e28', 'test1', 'test1', '4999.98', 'closed', NULL, '2026-05-26 11:13:21', '2026-01-31 18:30:00', '2026-02-20 18:30:00', '2026-02-05 01:40:00', 'public', 'sar', 'test99@gmail.com', NULL, 1144, 0, NULL, NULL, NULL, 'v1.0'),
